   		CLASS
   			EXPRESSION ([pixel]<=50)
			STYLE
				COLORRANGE '#440154' '#472a7a'
				DATARANGE 0.0 20.0
			END
		END
		CLASS
   			EXPRESSION ([pixel]>50.0 AND [pixel]<=80.0)
			STYLE
				COLORRANGE '#472a7a' '#39568c'
				DATARANGE 10 20
			END
		END
		CLASS
   			EXPRESSION ([pixel]>80.0 AND [pixel]<=120.0)
			STYLE
				COLORRANGE '#39568c' '#297b8e'
				DATARANGE 20.0 40.0
			END
		END
		CLASS
   			EXPRESSION ([pixel]>120.0 AND [pixel]<=180.0)
			STYLE
				COLORRANGE '#297b8e' '#1e9f89'
				DATARANGE 40 60
			END
		END
			
		CLASS
   			EXPRESSION ([pixel]>180 AND [pixel]<=240.0)
			STYLE
				COLORRANGE '#1e9f89' '#46c06f'
				DATARANGE 60.0 70.0
			END
		END
			
		CLASS
   			EXPRESSION ([pixel]>240.0 AND [pixel]<=280.0)
			STYLE
				COLORRANGE '#46c06f' '#9cd93b'
				DATARANGE 70.0 80.0
			END
			
		END
		CLASS
   			EXPRESSION ([pixel]>280.0)
   			STYLE
				COLORRANGE '#9cd93b' '#fde725'
				DATARANGE 80.0 150.0
			END
		END
